func HandleCommand(cmd string) error {
	switch cmd {
	case "create":
		return handleCreate()
	case "update":
		return handleUpdate()
	case "delete":
		return handleDelete()
	case "list":
		return handleList()
	case "get":
		return handleGet()
	case "export":
		return handleExport()
	case "import":
		return handleImport()
	case "sync":
		return handleSync()
	case "validate":
		return handleValidate()
	case "migrate":
		return handleMigrate()
	case "rollback":
		return handleRollback()
	case "status":
		return handleStatus()
	default:
		return fmt.Errorf("unknown command: %s", cmd)
	}
}
